"use client"
import { useEffect } from 'react'

const GENESIS_HTML = "<!DOCTYPE html>\n<html lang=\"en\">\n<head>\n<meta charset=\"UTF-8\">\n<meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n<title>SOVREND \u2014 GENESIS</title>\n<link href=\"https://fonts.googleapis.com/css2?family=Fraunces:ital,opsz,wght@0,9..144,100;0,9..144,200;0,9..144,300;0,9..144,700;0,9..144,900;1,9..144,100;1,9..144,200;1,9..144,300;1,9..144,400&family=DM+Sans:wght@200;300;400&family=JetBrains+Mono:wght@300;400&display=swap\" rel=\"stylesheet\">\n<style>\n*,*::before,*::after{margin:0;padding:0;box-sizing:border-box}\n:root{\n  /* The color of potential \u2014 neither light nor dark\n     Pre-dawn. The moment before the sun decides to exist. */\n  --pre:#0B0D14;\n  --becoming:#141820;\n  --almost:#1E2230;\n  --threshold:rgba(255,255,255,0.06);\n\n  /* The accent is not a color.\n     It is the light that appears when something becomes real. */\n  --genesis:#E8E4D8;\n  --genesis-warm:#F2EDD8;\n  --genesis-cold:#D4D8E8;\n  --signal:#FFFFFF;\n  --signal-dim:rgba(255,255,255,0.5);\n  --signal-ghost:rgba(255,255,255,0.12);\n\n  /* The moment color \u2014 amber-white, like a filament heating */\n  --moment:#FFE8A8;\n  --moment-dim:rgba(255,232,168,0.4);\n  --moment-ghost:rgba(255,232,168,0.08);\n}\nhtml{overflow-x:hidden;scroll-behavior:smooth}\nbody{\n  background:var(--pre);\n  color:var(--genesis);\n  font-family:'DM Sans',sans-serif;\n  cursor:none;\n  overflow-x:hidden;\n}\n\n/* ============================================================\n   THE CURSOR\n   Not a dot. Not a crosshair.\n   A point of potential \u2014 it assembles what it touches.\n   ============================================================ */\n#g-cursor{position:fixed;z-index:9999;pointer-events:none;mix-blend-mode:normal}\n.gc-core{\n  position:absolute;\n  width:4px;height:4px;\n  border-radius:50%;\n  background:var(--moment);\n  transform:translate(-50%,-50%);\n  box-shadow:0 0 8px var(--moment),0 0 20px rgba(255,232,168,0.4);\n  transition:transform 0.1s,box-shadow 0.2s;\n}\n.gc-field{\n  position:absolute;\n  width:60px;height:60px;\n  border-radius:50%;\n  border:1px solid rgba(255,232,168,0.15);\n  transform:translate(-50%,-50%);\n  transition:all 0.4s cubic-bezier(0.16,1,0.3,1);\n}\n.gc-field::before{\n  content:'';position:absolute;inset:12px;\n  border-radius:50%;\n  border:1px solid rgba(255,232,168,0.06);\n}\n/* Assembling particles that orbit the cursor */\n.gc-particle{\n  position:absolute;\n  width:2px;height:2px;\n  border-radius:50%;\n  background:var(--moment);\n  transform:translate(-50%,-50%);\n  opacity:0;\n}\n\n/* ============================================================\n   THE CANVAS\n   Not a background. A field of pre-existence.\n   Particles that haven't become anything yet.\n   ============================================================ */\n#g-canvas{position:fixed;inset:0;z-index:0;pointer-events:none}\n\n/* ============================================================\n   THE WORD ASSEMBLER\n   Text doesn't appear. It assembles from particles.\n   ============================================================ */\n.assembling{\n  display:inline-block;\n  position:relative;\n}\n.assembling-char{\n  display:inline-block;\n  opacity:0;\n  transform:translate(var(--tx,0px),var(--ty,0px)) scale(0.3);\n  filter:blur(8px);\n  transition:\n    opacity 0.6s cubic-bezier(0.16,1,0.3,1),\n    transform 0.8s cubic-bezier(0.16,1,0.3,1),\n    filter 0.6s cubic-bezier(0.16,1,0.3,1);\n}\n.assembling-char.assembled{\n  opacity:1;\n  transform:translate(0,0) scale(1);\n  filter:blur(0);\n}\n\n/* ============================================================\n   NAV \u2014 barely there until needed\n   ============================================================ */\n.g-nav{\n  position:fixed;top:0;left:0;right:0;z-index:100;\n  height:68px;display:flex;align-items:center;padding:0 56px;\n  transition:all 0.6s ease;\n}\n.g-nav.solid{\n  background:rgba(11,13,20,0.92);\n  backdrop-filter:blur(24px);\n  border-bottom:1px solid var(--threshold);\n}\n.g-nav-logo{\n  font-family:'Fraunces',serif;font-size:16px;font-weight:300;\n  letter-spacing:0.12em;text-transform:uppercase;\n  color:var(--genesis);text-decoration:none;\n  transition:letter-spacing 0.4s;\n}\n.g-nav-logo:hover{letter-spacing:0.18em}\n.g-nav-logo em{font-style:italic;font-weight:100;opacity:0.5}\n.g-nav-center{flex:1;display:flex;justify-content:center;gap:40px}\n.g-nav-center a{\n  font-size:11px;font-weight:300;letter-spacing:0.1em;\n  color:rgba(232,228,216,0.35);text-decoration:none;\n  transition:color 0.3s,letter-spacing 0.3s;\n}\n.g-nav-center a:hover{color:var(--genesis);letter-spacing:0.14em}\n.g-nav-cta{\n  font-family:'DM Sans',sans-serif;font-size:11px;font-weight:300;\n  letter-spacing:0.14em;text-transform:uppercase;\n  padding:10px 24px;\n  background:transparent;\n  border:1px solid rgba(255,232,168,0.2);\n  color:var(--moment);\n  cursor:none;transition:all 0.4s ease;\n}\n.g-nav-cta:hover{\n  background:rgba(255,232,168,0.06);\n  border-color:rgba(255,232,168,0.5);\n  box-shadow:0 0 24px rgba(255,232,168,0.15);\n}\n\n/* ============================================================\n   HERO \u2014 The moment of becoming\n   ============================================================ */\n.g-hero{\n  min-height:100vh;\n  display:flex;flex-direction:column;\n  justify-content:center;\n  padding:0 56px;\n  position:relative;z-index:1;\n  overflow:hidden;\n}\n\n/* The threshold line \u2014 a single horizontal element\n   that exists at the boundary between thought and thing */\n.g-threshold{\n  position:absolute;\n  left:0;right:0;\n  height:1px;\n  background:linear-gradient(\n    90deg,\n    transparent 0%,\n    rgba(255,232,168,0.03) 20%,\n    rgba(255,232,168,0.15) 50%,\n    rgba(255,232,168,0.03) 80%,\n    transparent 100%\n  );\n  top:50%;\n  animation:threshold-breathe 8s ease-in-out infinite;\n  pointer-events:none;\n}\n@keyframes threshold-breathe{\n  0%,100%{opacity:0.3;transform:scaleX(0.8)}\n  50%{opacity:1;transform:scaleX(1)}\n}\n\n/* The pre-existence field */\n.g-field{\n  position:absolute;inset:0;\n  background:\n    radial-gradient(ellipse 60% 40% at 50% 50%,\n      rgba(255,232,168,0.03) 0%,\n      transparent 70%),\n    radial-gradient(ellipse 30% 60% at 20% 30%,\n      rgba(255,255,255,0.02) 0%,\n      transparent 60%),\n    radial-gradient(ellipse 40% 30% at 80% 70%,\n      rgba(255,255,255,0.015) 0%,\n      transparent 60%);\n  animation:field-shift 12s ease-in-out infinite alternate;\n}\n@keyframes field-shift{\n  from{transform:scale(1) rotate(0deg)}\n  to{transform:scale(1.05) rotate(1deg)}\n}\n\n/* HERO CONTENT */\n.g-hero-pre{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.24em;text-transform:uppercase;\n  color:rgba(255,232,168,0.4);\n  margin-bottom:48px;\n  display:flex;align-items:center;gap:16px;\n  opacity:0;animation:g-appear 1s cubic-bezier(0.16,1,0.3,1) 0.3s forwards;\n}\n@keyframes g-appear{\n  from{opacity:0;transform:translateY(20px)}\n  to{opacity:1;transform:translateY(0)}\n}\n.g-pre-line{width:40px;height:1px;background:rgba(255,232,168,0.3)}\n.g-pre-dot{\n  width:4px;height:4px;border-radius:50%;\n  background:var(--moment);\n  animation:pre-pulse 2s ease-in-out infinite;\n}\n@keyframes pre-pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:0.3;transform:scale(0.5)}}\n\n.g-hero-h1{\n  font-family:'Fraunces',serif;\n  font-size:clamp(60px,9vw,132px);\n  font-weight:900;\n  line-height:0.88;\n  letter-spacing:-0.045em;\n  max-width:1000px;\n  margin-bottom:0;\n  position:relative;\n}\n\n/* Each line of the hero exists in a different state of becoming */\n.g-line{display:block;overflow:hidden;margin-bottom:4px}\n.g-line-inner{\n  display:block;\n  animation:g-line-rise 1s cubic-bezier(0.16,1,0.3,1) both;\n}\n.g-line:nth-child(1) .g-line-inner{animation-delay:0.5s;color:var(--genesis)}\n.g-line:nth-child(2) .g-line-inner{\n  animation-delay:0.65s;\n  /* This line exists between states \u2014 half formed */\n  color:transparent;\n  -webkit-text-stroke:0.5px rgba(232,228,216,0.3);\n  font-weight:100;font-style:italic;\n}\n.g-line:nth-child(3) .g-line-inner{\n  animation-delay:0.8s;\n  /* This line is the moment of becoming \u2014 warm light */\n  color:var(--moment);\n  font-style:italic;font-weight:200;\n}\n@keyframes g-line-rise{\n  from{\n    transform:translateY(100%) skewY(2deg);\n    opacity:0;\n    filter:blur(4px);\n  }\n  to{\n    transform:translateY(0) skewY(0);\n    opacity:1;\n    filter:blur(0);\n  }\n}\n\n/* THE THRESHOLD MOMENT\n   Between the headline and the subtext \u2014\n   a pause where something is deciding to exist */\n.g-pause{\n  height:64px;\n  position:relative;\n  display:flex;align-items:center;\n}\n.g-pause-line{\n  position:absolute;left:0;\n  height:1px;\n  background:linear-gradient(90deg,rgba(255,232,168,0.4),transparent);\n  animation:pause-grow 1.2s cubic-bezier(0.16,1,0.3,1) 1.2s both;\n}\n@keyframes pause-grow{from{width:0}to{width:280px}}\n.g-pause-moment{\n  position:absolute;left:0;\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.18em;color:rgba(255,232,168,0.3);\n  opacity:0;animation:g-appear 0.8s ease 1.6s forwards;\n}\n\n.g-hero-bottom{\n  display:flex;align-items:flex-end;justify-content:space-between;\n  opacity:0;animation:g-appear 1s cubic-bezier(0.16,1,0.3,1) 1.4s forwards;\n}\n.g-hero-sub{\n  font-size:17px;font-weight:200;\n  color:rgba(232,228,216,0.5);\n  line-height:1.8;max-width:500px;\n  letter-spacing:0.01em;\n}\n.g-hero-sub strong{color:var(--genesis);font-weight:300}\n.g-hero-actions{\n  display:flex;flex-direction:column;\n  align-items:flex-end;gap:16px;\n}\n\n/* CTA \u2014 The moment you cross the threshold */\n.g-cta-main{\n  font-family:'DM Sans',sans-serif;font-size:14px;font-weight:300;\n  letter-spacing:0.1em;\n  padding:18px 48px;\n  background:var(--moment);\n  color:#0B0D14;\n  border:none;cursor:none;\n  position:relative;overflow:hidden;\n  transition:all 0.5s cubic-bezier(0.16,1,0.3,1);\n}\n.g-cta-main::before{\n  content:'';position:absolute;inset:0;\n  background:linear-gradient(135deg,rgba(255,255,255,0.2),transparent);\n  opacity:0;transition:opacity 0.4s;\n}\n.g-cta-main:hover::before{opacity:1}\n.g-cta-main:hover{\n  box-shadow:\n    0 0 0 1px rgba(255,232,168,0.5),\n    0 0 40px rgba(255,232,168,0.3),\n    0 0 80px rgba(255,232,168,0.1);\n  transform:translateY(-2px);\n  letter-spacing:0.14em;\n}\n.g-cta-ghost{\n  font-size:12px;font-weight:200;letter-spacing:0.12em;\n  color:rgba(232,228,216,0.35);\n  background:transparent;border:none;cursor:none;\n  transition:all 0.3s;\n  display:flex;align-items:center;gap:8px;\n}\n.g-cta-ghost:hover{color:var(--genesis)}\n.g-cta-ghost::after{\n  content:'\u2192';\n  transition:transform 0.3s;\n}\n.g-cta-ghost:hover::after{transform:translateX(4px)}\n\n/* PROOF */\n.g-proof{\n  display:flex;align-items:center;gap:10px;\n  font-size:11px;font-weight:200;\n  color:rgba(232,228,216,0.25);letter-spacing:0.04em;\n}\n.g-avs{display:flex}\n.g-av{\n  width:24px;height:24px;border-radius:50%;\n  border:1px solid var(--pre);\n  margin-left:-5px;font-size:8px;font-weight:400;\n  display:flex;align-items:center;justify-content:center;\n}\n.g-av:first-child{margin-left:0}\n.ga1{background:#1a2a1e;color:rgba(77,255,133,0.8)}\n.ga2{background:#1a1e2a;color:rgba(77,160,255,0.8)}\n.ga3{background:#2a1a2a;color:rgba(200,100,255,0.8)}\n.ga4{background:#2a1e1a;color:rgba(255,160,77,0.8)}\n.ga5{background:#1e1a2a;color:rgba(140,100,255,0.8)}\n\n/* ============================================================\n   THE SCROLL INDICATOR\n   Not an arrow. A thread being pulled into existence.\n   ============================================================ */\n.g-thread{\n  position:absolute;bottom:40px;left:56px;\n  display:flex;align-items:center;gap:16px;\n  opacity:0;animation:g-appear 1s ease 2s forwards;\n}\n.g-thread-line{\n  width:1px;\n  background:linear-gradient(var(--moment),transparent);\n  animation:thread-grow 2s ease-in-out infinite;\n}\n@keyframes thread-grow{\n  0%{height:40px;opacity:0.4}\n  50%{height:60px;opacity:1}\n  100%{height:40px;opacity:0.4}\n}\n.g-thread-text{\n  font-family:'JetBrains Mono',monospace;font-size:8px;\n  letter-spacing:0.22em;text-transform:uppercase;\n  color:rgba(232,228,216,0.2);\n  writing-mode:vertical-rl;transform:rotate(180deg);\n}\n\n/* ============================================================\n   BECOMING SECTION\n   The section where things materialize\n   ============================================================ */\n.g-becoming{\n  padding:160px 56px;\n  position:relative;z-index:1;\n}\n.g-becoming-grid{\n  display:grid;grid-template-columns:1fr 1fr;\n  gap:120px;align-items:start;\n}\n\n/* The materialization numbers \u2014 they feel like they just arrived */\n.g-becoming-left{}\n.g-becoming-label{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.22em;text-transform:uppercase;\n  color:rgba(255,232,168,0.3);margin-bottom:24px;\n  display:flex;align-items:center;gap:12px;\n}\n.g-becoming-label::before{\n  content:'';width:1px;height:20px;\n  background:linear-gradient(var(--moment),transparent);\n}\n.g-becoming-h{\n  font-family:'Fraunces',serif;\n  font-size:clamp(40px,5vw,64px);\n  font-weight:700;line-height:1.0;\n  letter-spacing:-0.03em;\n  color:var(--genesis);margin-bottom:28px;\n}\n.g-becoming-h em{\n  font-style:italic;font-weight:100;\n  color:rgba(232,228,216,0.4);\n}\n.g-becoming-body{\n  font-size:16px;font-weight:200;\n  color:rgba(232,228,216,0.45);\n  line-height:1.85;max-width:460px;\n}\n\n/* The state panels \u2014 each shows a different stage of becoming */\n.g-states{display:flex;flex-direction:column;gap:1px;margin-top:0}\n.g-state{\n  position:relative;padding:32px 0;\n  border-bottom:1px solid var(--threshold);\n  cursor:none;\n  overflow:hidden;\n}\n.g-state:first-child{border-top:1px solid var(--threshold)}\n.g-state-progress{\n  position:absolute;left:0;top:0;bottom:0;width:0;\n  background:linear-gradient(90deg,rgba(255,232,168,0.03),transparent);\n  transition:width 0.6s cubic-bezier(0.16,1,0.3,1);\n}\n.g-state:hover .g-state-progress{width:100%}\n.g-state-num{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.18em;color:rgba(255,232,168,0.25);\n  margin-bottom:12px;\n}\n.g-state-title{\n  font-family:'Fraunces',serif;font-size:24px;font-weight:600;\n  color:var(--genesis);letter-spacing:-0.02em;\n  margin-bottom:8px;line-height:1.2;\n}\n.g-state-desc{\n  font-size:14px;font-weight:200;\n  color:rgba(232,228,216,0.4);line-height:1.7;\n}\n.g-state-indicator{\n  position:absolute;right:0;top:50%;transform:translateY(-50%);\n  width:6px;height:6px;border-radius:50%;\n  background:var(--moment);opacity:0;\n  box-shadow:0 0 12px var(--moment);\n  transition:opacity 0.3s;\n}\n.g-state:hover .g-state-indicator{opacity:1}\n\n/* ============================================================\n   THE MOMENT SECTION\n   Where things that existed in imagination become real\n   ============================================================ */\n.g-moment-section{\n  padding:0 56px 160px;\n  position:relative;z-index:1;\n}\n.g-moment-label{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.22em;text-transform:uppercase;\n  color:rgba(255,232,168,0.3);margin-bottom:64px;\n  display:flex;align-items:center;gap:12px;\n}\n.g-moment-label::before{content:'';width:1px;height:20px;background:linear-gradient(var(--moment),transparent)}\n\n/* The existence grid \u2014 things materializing */\n.g-exist-grid{\n  display:grid;grid-template-columns:repeat(3,1fr);\n  gap:1px;\n  background:var(--threshold);\n  position:relative;\n}\n.g-exist-grid::before{\n  content:'';position:absolute;inset:-1px;\n  background:linear-gradient(135deg,rgba(255,232,168,0.05),transparent,rgba(255,232,168,0.03));\n  pointer-events:none;z-index:1;\n}\n.g-exist{\n  background:var(--pre);\n  padding:48px 40px;\n  position:relative;overflow:hidden;\n  cursor:none;transition:background 0.5s ease;\n}\n.g-exist:hover{background:var(--becoming)}\n\n/* The materialization effect on hover */\n.g-exist-mat{\n  position:absolute;inset:0;\n  background:radial-gradient(circle at var(--mx,50%) var(--my,50%),\n    rgba(255,232,168,0.04) 0%,transparent 60%);\n  opacity:0;transition:opacity 0.3s;\n  pointer-events:none;\n}\n.g-exist:hover .g-exist-mat{opacity:1}\n\n.g-exist-pre{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.18em;text-transform:uppercase;\n  color:rgba(255,232,168,0.25);margin-bottom:28px;\n  position:relative;z-index:1;\n}\n.g-exist-num{\n  font-family:'Fraunces',serif;font-size:64px;font-weight:900;\n  color:transparent;-webkit-text-stroke:0.5px rgba(232,228,216,0.15);\n  line-height:1;margin-bottom:16px;\n  position:relative;z-index:1;letter-spacing:-0.04em;\n}\n.g-exist:hover .g-exist-num{\n  -webkit-text-stroke-color:rgba(255,232,168,0.4);\n}\n.g-exist-title{\n  font-family:'Fraunces',serif;font-size:22px;font-weight:600;\n  color:var(--genesis);letter-spacing:-0.02em;line-height:1.15;\n  margin-bottom:12px;position:relative;z-index:1;\n}\n.g-exist-body{\n  font-size:14px;font-weight:200;\n  color:rgba(232,228,216,0.4);line-height:1.7;\n  position:relative;z-index:1;\n}\n\n/* ============================================================\n   THE PROOF SECTION\n   Things that became real\n   ============================================================ */\n.g-proof-section{\n  padding:80px 56px 120px;\n  border-top:1px solid var(--threshold);\n  position:relative;z-index:1;\n}\n.g-proof-header{\n  display:flex;align-items:flex-end;justify-content:space-between;\n  margin-bottom:56px;\n}\n.g-proof-h{\n  font-family:'Fraunces',serif;font-size:48px;font-weight:700;\n  letter-spacing:-0.03em;color:var(--genesis);\n}\n.g-proof-h em{font-style:italic;font-weight:100;color:rgba(232,228,216,0.35)}\n.g-proof-note{\n  font-size:12px;font-weight:200;color:rgba(232,228,216,0.25);\n  letter-spacing:0.06em;max-width:200px;text-align:right;\n  line-height:1.6;\n}\n\n/* Evidence cards \u2014 different from every other testimonial ever designed\n   They feel like artifacts. Documents. Evidence of existence. */\n.g-evidence{display:grid;grid-template-columns:repeat(3,1fr);gap:1px;background:var(--threshold)}\n.g-evidence-item{\n  background:var(--pre);padding:36px;\n  position:relative;overflow:hidden;\n  cursor:none;transition:background 0.4s;\n}\n.g-evidence-item:hover{background:var(--becoming)}\n.g-evidence-item::before{\n  content:'';position:absolute;top:0;left:0;right:0;height:1px;\n  background:linear-gradient(90deg,transparent,rgba(255,232,168,0.15),transparent);\n  opacity:0;transition:opacity 0.4s;\n}\n.g-evidence-item:hover::before{opacity:1}\n\n/* The \"became real\" moment */\n.g-evidence-moment{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.14em;text-transform:uppercase;\n  color:rgba(255,232,168,0.3);\n  display:flex;align-items:center;gap:8px;\n  margin-bottom:20px;\n}\n.g-evidence-moment::before{\n  content:'';width:14px;height:1px;\n  background:rgba(255,232,168,0.3);\n}\n.g-evidence-quote{\n  font-family:'Fraunces',serif;font-size:17px;\n  font-weight:300;font-style:italic;\n  color:rgba(232,228,216,0.7);line-height:1.65;\n  margin-bottom:24px;\n  letter-spacing:0.005em;\n}\n.g-evidence-from{\n  font-size:12px;font-weight:200;color:rgba(232,228,216,0.3);\n}\n.g-evidence-name{color:rgba(232,228,216,0.6);font-weight:300}\n.g-evidence-outcome{\n  display:inline-flex;align-items:center;gap:6px;\n  margin-top:12px;\n  font-family:'JetBrains Mono',monospace;font-size:10px;\n  color:var(--moment);letter-spacing:0.08em;\n  opacity:0.7;\n}\n.g-evidence-outcome::before{\n  content:'';width:20px;height:1px;background:var(--moment);opacity:0.4;\n}\n\n/* ============================================================\n   THE FINAL THRESHOLD\n   The last moment before they decide to build\n   ============================================================ */\n.g-final{\n  padding:160px 56px;\n  text-align:center;\n  position:relative;z-index:1;\n  overflow:hidden;\n  border-top:1px solid var(--threshold);\n}\n.g-final-field{\n  position:absolute;inset:0;\n  background:radial-gradient(ellipse 70% 70% at 50% 50%,\n    rgba(255,232,168,0.04) 0%,transparent 70%);\n  animation:field-shift 10s ease-in-out infinite alternate;\n}\n.g-final-pre{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.22em;text-transform:uppercase;\n  color:rgba(255,232,168,0.25);margin-bottom:32px;\n  position:relative;z-index:1;\n}\n.g-final-h{\n  font-family:'Fraunces',serif;\n  font-size:clamp(64px,10vw,140px);\n  font-weight:900;line-height:0.88;\n  letter-spacing:-0.05em;\n  margin-bottom:0;\n  position:relative;z-index:1;\n}\n.g-final-line1{display:block;color:var(--genesis)}\n.g-final-line2{\n  display:block;\n  color:transparent;\n  -webkit-text-stroke:0.5px rgba(232,228,216,0.2);\n  font-weight:100;font-style:italic;\n}\n.g-final-line3{\n  display:block;color:var(--moment);\n  font-style:italic;font-weight:200;\n}\n.g-final-pause{height:56px;position:relative;z-index:1}\n.g-final-sub{\n  font-size:17px;font-weight:200;color:rgba(232,228,216,0.35);\n  margin-bottom:56px;position:relative;z-index:1;letter-spacing:0.02em;\n}\n.g-final-btn{\n  font-family:'DM Sans',sans-serif;font-size:14px;font-weight:300;\n  letter-spacing:0.14em;\n  padding:20px 64px;\n  background:var(--moment);color:#0B0D14;\n  border:none;cursor:none;\n  transition:all 0.5s cubic-bezier(0.16,1,0.3,1);\n  position:relative;z-index:1;display:inline-block;\n  margin-bottom:32px;\n}\n.g-final-btn:hover{\n  letter-spacing:0.2em;\n  box-shadow:0 0 0 1px rgba(255,232,168,0.5),0 0 60px rgba(255,232,168,0.3);\n  transform:translateY(-3px);\n}\n.g-final-trust{\n  display:flex;justify-content:center;gap:40px;\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.14em;color:rgba(232,228,216,0.15);\n  position:relative;z-index:1;text-transform:uppercase;\n}\n\n/* FOOTER */\n.g-footer{\n  padding:32px 56px;\n  border-top:1px solid var(--threshold);\n  display:flex;justify-content:space-between;align-items:center;\n  position:relative;z-index:1;\n}\n.g-footer-logo{\n  font-family:'Fraunces',serif;font-size:14px;font-weight:300;\n  letter-spacing:0.14em;text-transform:uppercase;color:rgba(232,228,216,0.4);\n}\n.g-footer-logo em{font-style:italic;font-weight:100;opacity:0.5}\n.g-footer-copy{\n  font-family:'JetBrains Mono',monospace;font-size:9px;\n  letter-spacing:0.12em;color:rgba(232,228,216,0.15);\n}\n\n/* REVEAL */\n.g-reveal{\n  opacity:0;transform:translateY(40px);\n  transition:opacity 1s cubic-bezier(0.16,1,0.3,1),transform 1s cubic-bezier(0.16,1,0.3,1);\n}\n.g-reveal.in{opacity:1;transform:none}\n.g-reveal:nth-child(2){transition-delay:0.12s}\n.g-reveal:nth-child(3){transition-delay:0.24s}\n.g-reveal:nth-child(4){transition-delay:0.36s}\n\n/* \u2500\u2500 INTAKE COMPONENTS \u2500\u2500 */\n@keyframes fadeUp{from{opacity:0;transform:translateY(20px)}to{opacity:1;transform:none}}\n@keyframes pulse{0%,100%{opacity:1;transform:scale(1)}50%{opacity:0.3;transform:scale(0.4)}}\n\n.istep{display:none;animation:fadeUp 0.38s cubic-bezier(0.16,1,0.3,1) forwards}\n.istep.active{display:block}\n\n.pcard{\n  background:var(--becoming);border:1px solid var(--threshold);\n  padding:22px 20px;cursor:pointer;transition:all 0.3s;\n  position:relative;overflow:hidden;\n}\n.pcard::before{content:'';position:absolute;inset:0;background:var(--moment-ghost);opacity:0;transition:opacity 0.3s}\n.pcard:hover::before,.pcard.on::before{opacity:1}\n.pcard.on{border-color:rgba(255,232,168,0.35)}\n.pcheck{\n  position:absolute;top:12px;right:12px;\n  width:16px;height:16px;border-radius:50%;\n  background:var(--moment);color:#0B0D14;\n  font-size:8px;font-weight:700;\n  display:flex;align-items:center;justify-content:center;\n  opacity:0;transition:opacity 0.2s;\n}\n.pcard.on .pcheck{opacity:1}\n\n.vcard{\n  background:var(--becoming);border:1px solid var(--threshold);\n  cursor:pointer;transition:border-color 0.3s;position:relative;overflow:hidden;\n}\n.vcard.on{border-color:rgba(255,232,168,0.35)}\n.vcheck{\n  position:absolute;top:8px;right:8px;\n  width:16px;height:16px;border-radius:50%;\n  background:var(--moment);color:#0B0D14;\n  font-size:8px;font-weight:700;\n  display:flex;align-items:center;justify-content:center;\n  opacity:0;transition:opacity 0.2s;\n}\n.vcard.on .vcheck{opacity:1}\n\n.acard{\n  background:var(--becoming);border:1px solid var(--threshold);\n  padding:16px 16px 14px;cursor:pointer;transition:all 0.3s;position:relative;\n}\n.acard.on{border-color:rgba(255,232,168,0.35);background:var(--moment-ghost)}\n.acheck{\n  position:absolute;top:10px;right:10px;\n  width:14px;height:14px;border-radius:50%;\n  background:var(--moment);color:#0B0D14;\n  font-size:7px;font-weight:700;\n  display:flex;align-items:center;justify-content:center;\n  opacity:0;transition:opacity 0.2s;\n}\n.acard.on .acheck{opacity:1}\n\n.ifield{\n  width:100%;padding:14px 16px;\n  background:var(--becoming);border:1px solid var(--threshold);\n  color:var(--genesis);font-family:'DM Sans',sans-serif;\n  font-size:15px;font-weight:300;outline:none;\n  transition:border-color 0.3s,background 0.3s;\n  -webkit-appearance:none;border-radius:0;resize:none;\n  line-height:1.65;\n}\n.ifield::placeholder{color:rgba(232,228,216,0.18)}\n.ifield:focus{border-color:rgba(255,232,168,0.28);background:rgba(255,232,168,0.03)}\n.ifield.valid{border-color:rgba(46,125,82,0.5);background:rgba(46,125,82,0.06)}\n.ifield.err{border-color:rgba(184,50,50,0.5);background:rgba(184,50,50,0.06)}\n\n.inav{display:flex;gap:8px;align-items:center}\n.ibtn-next{\n  flex:1;padding:16px;background:var(--moment);color:#0B0D14;\n  border:none;font-family:'DM Sans',sans-serif;font-size:12px;\n  font-weight:500;letter-spacing:0.12em;text-transform:uppercase;\n  cursor:pointer;transition:all 0.3s;\n}\n.ibtn-next:hover{box-shadow:0 8px 28px rgba(255,232,168,0.22)}\n.ibtn-next:disabled{opacity:0.3;cursor:not-allowed;box-shadow:none}\n.ibtn-back{\n  padding:16px 18px;background:none;\n  border:1px solid var(--threshold);color:rgba(232,228,216,0.35);\n  font-family:'JetBrains Mono',monospace;font-size:10px;\n  letter-spacing:0.12em;text-transform:uppercase;cursor:pointer;\n  transition:all 0.3s;\n}\n.ibtn-back:hover{border-color:rgba(232,228,216,0.2);color:rgba(232,228,216,0.6)}\n.ibtn-build{\n  width:100%;padding:18px;background:var(--moment);color:#0B0D14;\n  border:none;font-family:'DM Sans',sans-serif;font-size:13px;\n  font-weight:500;letter-spacing:0.14em;text-transform:uppercase;\n  cursor:pointer;transition:all 0.4s;\n}\n.ibtn-build:hover{box-shadow:0 12px 40px rgba(255,232,168,0.28)}\n\n.prog-seg{flex:1;height:1px;background:var(--threshold);transition:background 0.5s,box-shadow 0.5s}\n.prog-seg.done{background:rgba(255,232,168,0.35)}\n.prog-seg.active{background:var(--moment);box-shadow:0 0 7px rgba(255,232,168,0.3)}\n\n.tcursor{\n  display:inline-block;width:2px;height:12px;\n  background:rgba(0,229,255,0.5);\n  animation:blink 0.9s step-end infinite;\n  vertical-align:middle;margin-left:2px;\n}\n@keyframes blink{0%,100%{opacity:1}50%{opacity:0}}\n\n.spec-row{display:flex;align-items:flex-start;padding:11px 22px;border-bottom:1px solid var(--threshold)}\n.spec-row:last-child{border-bottom:none}\n.spec-k{font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.16em;text-transform:uppercase;color:rgba(232,228,216,0.28);width:84px;flex-shrink:0;padding-top:2px}\n.spec-v{font-size:13px;font-weight:300;color:var(--genesis);flex:1;line-height:1.5}\n.spec-tag{display:inline-block;font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.10em;text-transform:uppercase;padding:2px 7px;background:rgba(255,232,168,0.06);border:1px solid rgba(255,232,168,0.12);color:rgba(255,232,168,0.45);margin:1px 2px 1px 0}\n\n.gap-flag{display:flex;align-items:flex-start;gap:10px;padding:11px 14px;background:rgba(184,50,50,0.04);border:1px solid rgba(184,50,50,0.12);border-left:2px solid rgba(184,50,50,0.3);margin-bottom:5px}\n.gap-icon{font-family:'JetBrains Mono',monospace;font-size:8px;color:rgba(184,50,50,0.5);flex-shrink:0;padding-top:2px}\n.gap-txt{font-size:12px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.6}\n.gap-txt strong{color:rgba(184,50,50,0.6);font-weight:300}\n\n.layer-row{display:flex;align-items:center;gap:14px;padding:12px 16px;background:var(--becoming);border-left:2px solid var(--threshold);transition:all 0.4s;margin-bottom:2px}\n.layer-row.active{border-left-color:rgba(0,229,255,0.5);background:rgba(0,229,255,0.025)}\n.layer-row.done{border-left-color:rgba(255,232,168,0.2)}\n.lspin{width:9px;height:9px;border:1px solid rgba(0,229,255,0.2);border-top-color:#00E5FF;border-radius:50%;animation:spin 0.8s linear infinite;display:none;flex-shrink:0}\n@keyframes spin{to{transform:rotate(360deg)}}\n.layer-row.active .lspin{display:block}\n\n@media(max-width:600px){\n  #cipher-hero{padding:100px 16px 60px}\n  .pcard,.vcard,.acard{font-size:13px}\n  .ifield{font-size:14px}\n}\n\n</style>\n</head>\n<body>\n\n<div id=\"g-cursor\">\n  <div class=\"gc-core\"></div>\n  <div class=\"gc-field\"></div>\n</div>\n\n<canvas id=\"g-canvas\"></canvas>\n\n<!-- NAV -->\n<nav class=\"g-nav\" id=\"g-nav\">\n  <a href=\"#\" class=\"g-nav-logo\">SOVREND</a>\n  <div class=\"g-nav-center\">\n    <a href=\"#how\">How it works</a>\n    <a href=\"#builds\">What gets built</a>\n    <a href=\"#proof\">Results</a>\n    <a href=\"#\">Pricing</a>\n  </div>\n  <button class=\"g-nav-cta\" onclick=\"document.getElementById('cipher-hero').scrollIntoView({behavior:'smooth'})\">Start building \u2192</button>\n</nav>\n\n<!-- CIPHER HERO INTAKE -->\n<section class=\"g-hero\" id=\"cipher-hero\" style=\"min-height:100vh;display:flex;flex-direction:column;align-items:center;justify-content:center;padding:120px 24px 80px;position:relative;z-index:1\">\n\n  <!-- CIPHER PRESENCE -->\n  <div class=\"cipher-intro\" style=\"width:100%;max-width:600px;margin-bottom:40px;opacity:0;animation:fadeUp 0.8s ease 0.3s forwards\">\n    <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.26em;text-transform:uppercase;color:rgba(255,232,168,0.3);display:flex;align-items:center;gap:12px;margin-bottom:28px;justify-content:center\">\n      <div style=\"width:36px;height:1px;background:rgba(255,232,168,0.2)\"></div>\n      <div style=\"width:5px;height:5px;border-radius:50%;background:var(--moment);box-shadow:0 0 8px var(--moment);animation:pulse 2s infinite\"></div>\n      Cipher is ready\n      <div style=\"width:36px;height:1px;background:rgba(255,232,168,0.2)\"></div>\n    </div>\n    <h1 style=\"font-family:'Fraunces',serif;font-size:clamp(44px,7vw,72px);font-weight:900;line-height:0.88;letter-spacing:-0.048em;text-align:center;margin-bottom:16px\">\n      What are you<br><em style=\"font-style:italic;font-weight:200;color:var(--moment)\">building?</em>\n    </h1>\n    <p style=\"font-size:16px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.75;text-align:center;max-width:440px;margin:0 auto\">\n      Tell me what you see. I will handle the rest \u2014 design, code, interactions, everything. No technical knowledge required.\n    </p>\n  </div>\n\n  <!-- CIPHER VOICE BAR -->\n  <div style=\"width:100%;max-width:600px;margin-bottom:36px;opacity:0;animation:fadeUp 0.8s ease 0.5s forwards\">\n    <div style=\"background:var(--becoming);border:1px solid var(--threshold);border-top:2px solid rgba(0,229,255,0.15);padding:22px 26px;display:flex;gap:16px;align-items:flex-start\">\n      <div style=\"width:32px;height:32px;border-radius:50%;border:1px solid rgba(0,229,255,0.22);background:rgba(0,229,255,0.04);display:flex;align-items:center;justify-content:center;flex-shrink:0\">\n        <div style=\"width:10px;height:10px;border-radius:50%;background:#00E5FF;box-shadow:0 0 8px #00E5FF\"></div>\n      </div>\n      <div style=\"flex:1\">\n        <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.20em;text-transform:uppercase;color:rgba(0,229,255,0.35);margin-bottom:8px\">Cipher &mdash; Your build architect</div>\n        <div id=\"cipherVoice\" style=\"font-size:14px;font-weight:200;color:var(--genesis);line-height:1.72\"><span class=\"tcursor\"></span></div>\n      </div>\n    </div>\n  </div>\n\n  <!-- INTAKE FORM -->\n  <div id=\"intakeWrap\" style=\"width:100%;max-width:600px;opacity:0;animation:fadeUp 0.8s ease 0.7s forwards\">\n\n    <!-- PROGRESS -->\n    <div style=\"display:flex;align-items:center;gap:4px;margin-bottom:36px\" id=\"progRow\"></div>\n\n    <!-- STEP 0: PATH -->\n    <div class=\"istep active\" id=\"is0\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 01 of 07 &mdash; Direction</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">Every path leads to the <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">same quality.</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">This tells me how to structure everything that follows.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:6px\" id=\"pathGrid\">\n        <div class=\"pcard\" data-path=\"product\" onclick=\"pickPath(this)\">\n          <div class=\"pcheck\">&#10003;</div>\n          <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.14em;color:rgba(255,232,168,0.22);margin-bottom:12px\">01</div>\n          <div style=\"font-family:'Fraunces',serif;font-size:19px;font-weight:700;letter-spacing:-0.025em;margin-bottom:6px;line-height:1.1\">Selling<br>something</div>\n          <div style=\"font-size:12px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.6\">A product, course, or physical good with a price attached.</div>\n          <div style=\"margin-top:10px;font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.10em;color:rgba(232,228,216,0.15);line-height:1.8\">Coffee &bull; Art &bull; Courses &bull; Merch</div>\n        </div>\n        <div class=\"pcard\" data-path=\"service\" onclick=\"pickPath(this)\">\n          <div class=\"pcheck\">&#10003;</div>\n          <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.14em;color:rgba(255,232,168,0.22);margin-bottom:12px\">02</div>\n          <div style=\"font-family:'Fraunces',serif;font-size:19px;font-weight:700;letter-spacing:-0.025em;margin-bottom:6px;line-height:1.1\">Selling<br>expertise</div>\n          <div style=\"font-size:12px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.6\">You are the product. Your skill is what people are buying.</div>\n          <div style=\"margin-top:10px;font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.10em;color:rgba(232,228,216,0.15);line-height:1.8\">Coaching &bull; Design &bull; Consulting</div>\n        </div>\n        <div class=\"pcard\" data-path=\"software\" onclick=\"pickPath(this)\">\n          <div class=\"pcheck\">&#10003;</div>\n          <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.14em;color:rgba(255,232,168,0.22);margin-bottom:12px\">03</div>\n          <div style=\"font-family:'Fraunces',serif;font-size:19px;font-weight:700;letter-spacing:-0.025em;margin-bottom:6px;line-height:1.1\">Launching<br>software</div>\n          <div style=\"font-size:12px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.6\">An app, tool, or SaaS that needs the world to see it properly.</div>\n          <div style=\"margin-top:10px;font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.10em;color:rgba(232,228,216,0.15);line-height:1.8\">SaaS &bull; Mobile apps &bull; AI tools</div>\n        </div>\n        <div class=\"pcard\" data-path=\"launch\" onclick=\"pickPath(this)\">\n          <div class=\"pcheck\">&#10003;</div>\n          <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.14em;color:rgba(255,232,168,0.22);margin-bottom:12px\">04</div>\n          <div style=\"font-family:'Fraunces',serif;font-size:19px;font-weight:700;letter-spacing:-0.025em;margin-bottom:6px;line-height:1.1\">Launching<br>an idea</div>\n          <div style=\"font-size:12px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.6\">It does not fully exist yet. Validating, raising, or pre-launch.</div>\n          <div style=\"margin-top:10px;font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.10em;color:rgba(232,228,216,0.15);line-height:1.8\">Waitlists &bull; MVP &bull; Fundraising</div>\n        </div>\n      </div>\n      <div id=\"pathHint\" style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.12em;color:rgba(232,228,216,0.22);margin-top:10px\">Choose your path to continue.</div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-next\" id=\"btn0\" onclick=\"goStep(1)\" disabled>Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 1: NAME + DESCRIPTION -->\n    <div class=\"istep\" id=\"is1\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 02 of 07 &mdash; Foundation</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">Name it.<br><em style=\"font-style:italic;font-weight:200;color:var(--moment)\">Define it.</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">One precise name and one honest sentence is everything I need to begin.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div style=\"margin-bottom:12px\">\n        <label style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.20em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px\">Brand or project name</label>\n        <input id=\"iName\" class=\"ifield\" type=\"text\" placeholder=\"What is it called?\" oninput=\"validateName()\" onkeydown=\"enterNext(event,2)\">\n      </div>\n      <div style=\"margin-bottom:6px\">\n        <label id=\"descLabel\" style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.20em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px\">What it does</label>\n        <textarea id=\"iDesc\" class=\"ifield\" rows=\"3\" placeholder=\"One sentence. Who it is for and what it does for them.\" oninput=\"validateDesc()\"></textarea>\n      </div>\n      <div id=\"nameHint\" style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.12em;color:rgba(232,228,216,0.22);min-height:14px\"></div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(0)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn1\" onclick=\"goStep(2)\" disabled>Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 2: OFFERINGS -->\n    <div class=\"istep\" id=\"is2\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 03 of 07 &mdash; Architecture</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">What you offer<br>is the <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">structure.</em></h2>\n      <p id=\"s2sub\" style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">Everything I build will be structured around what you offer.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div id=\"s2content\"></div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(1)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn2\" onclick=\"goStep(3)\">Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 3: AESTHETIC -->\n    <div class=\"istep\" id=\"is3\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 04 of 07 &mdash; Direction</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">The best products are <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">felt</em><br>before they are understood.</h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">Choose the territory. Every design decision follows from this.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:5px;margin-bottom:12px\">\n        <div class=\"vcard\" data-vibe=\"dark\" onclick=\"pickVibe(this)\">\n          <div class=\"vcheck\">&#10003;</div>\n          <div style=\"height:48px;background:linear-gradient(120deg,#060810,#0F1520,rgba(0,229,255,0.12))\"></div>\n          <div style=\"padding:13px 15px 15px\">\n            <div style=\"font-family:'Fraunces',serif;font-size:15px;font-weight:700;letter-spacing:-0.02em;margin-bottom:4px\">Dark &amp; Cinematic</div>\n            <div style=\"font-size:11px;font-weight:200;color:rgba(232,228,216,0.4)\">Premium, minimal. Built to command attention.</div>\n          </div>\n        </div>\n        <div class=\"vcard\" data-vibe=\"light\" onclick=\"pickVibe(this)\">\n          <div class=\"vcheck\">&#10003;</div>\n          <div style=\"height:48px;background:linear-gradient(120deg,#F8F4EC,#E8E4D8,rgba(27,75,138,0.25))\"></div>\n          <div style=\"padding:13px 15px 15px\">\n            <div style=\"font-family:'Fraunces',serif;font-size:15px;font-weight:700;letter-spacing:-0.02em;margin-bottom:4px\">Light &amp; Editorial</div>\n            <div style=\"font-size:11px;font-weight:200;color:rgba(232,228,216,0.4)\">Warm, refined. The language of trusted authority.</div>\n          </div>\n        </div>\n        <div class=\"vcard\" data-vibe=\"bold\" onclick=\"pickVibe(this)\">\n          <div class=\"vcheck\">&#10003;</div>\n          <div style=\"height:48px;background:linear-gradient(120deg,#0A0808,#1A0A06,#C4622D)\"></div>\n          <div style=\"padding:13px 15px 15px\">\n            <div style=\"font-family:'Fraunces',serif;font-size:15px;font-weight:700;letter-spacing:-0.02em;margin-bottom:4px\">Bold &amp; Modern</div>\n            <div style=\"font-size:11px;font-weight:200;color:rgba(232,228,216,0.4)\">High-energy, high-contrast. Refuses to whisper.</div>\n          </div>\n        </div>\n        <div class=\"vcard\" data-vibe=\"organic\" onclick=\"pickVibe(this)\">\n          <div class=\"vcheck\">&#10003;</div>\n          <div style=\"height:48px;background:linear-gradient(120deg,#080E08,#0E1A0E,#3D5A3E)\"></div>\n          <div style=\"padding:13px 15px 15px\">\n            <div style=\"font-family:'Fraunces',serif;font-size:15px;font-weight:700;letter-spacing:-0.02em;margin-bottom:4px\">Warm &amp; Organic</div>\n            <div style=\"font-size:11px;font-weight:200;color:rgba(232,228,216,0.4)\">Natural, earthy. Built for trust that takes time.</div>\n          </div>\n        </div>\n      </div>\n      <label style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px\">Or name a brand yours should feel like (optional)</label>\n      <input id=\"iRef\" class=\"ifield\" type=\"text\" placeholder=\"e.g. Stripe, La Colombe, Linear, Apple\">\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(2)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn3\" onclick=\"goStep(4)\" disabled>Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 4: CTA -->\n    <div class=\"istep\" id=\"is4\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 05 of 07 &mdash; Conversion</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">Every page<br>has <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">one job.</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">Every section I build points toward this moment. What action do you want?</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div style=\"display:grid;grid-template-columns:1fr 1fr;gap:5px\" id=\"actionGrid\"></div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(3)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn4\" onclick=\"goStep(5)\" disabled>Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 5: DISTINCTION -->\n    <div class=\"istep\" id=\"is5\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 06 of 07 &mdash; Distinction</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">Why you<br>and <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">no one else?</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">Generic in, generic out. The more specific you are here, the more yours it feels on first render.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <textarea id=\"iEdge\" class=\"ifield\" rows=\"5\" placeholder=\"Who is your ideal customer? What do they struggle with before they find you? What do you do that nobody else does? What should they feel the moment they land?\" oninput=\"validateEdge()\"></textarea>\n      <div id=\"edgeHint\" style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.12em;color:rgba(232,228,216,0.22);margin-top:8px\">The more honest and specific, the stronger the build.</div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(4)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn5\" onclick=\"goStep(6)\" disabled>Continue &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 6: CLARIFY -->\n    <div class=\"istep\" id=\"is6\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Step 07 of 07 &mdash; Precision</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">One more<br><em style=\"font-style:italic;font-weight:200;color:var(--moment)\">before we build.</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">This answer shapes your hero copy. The more specific, the more yours it feels.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div style=\"background:var(--becoming);border:1px solid var(--threshold);border-left:2px solid rgba(255,232,168,0.3);padding:24px;margin-bottom:6px\">\n        <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.20em;text-transform:uppercase;color:rgba(255,232,168,0.28);margin-bottom:12px;display:flex;align-items:center;gap:8px\">\n          <span style=\"width:1px;height:14px;background:linear-gradient(rgba(255,232,168,0.4),transparent);display:inline-block;flex-shrink:0\"></span>\n          Cipher is asking\n        </div>\n        <div id=\"clarifyQ\" style=\"font-family:'Fraunces',serif;font-size:clamp(16px,2.5vw,20px);font-weight:700;letter-spacing:-0.025em;line-height:1.15;color:var(--genesis);margin-bottom:16px\">What is the one feeling you want someone to have the moment they land?</div>\n        <textarea id=\"iClarify\" class=\"ifield\" rows=\"3\" placeholder=\"Be specific. This becomes your hero headline direction.\" oninput=\"validateClarify()\"></textarea>\n      </div>\n      <div class=\"inav\" style=\"margin-top:28px\">\n        <button class=\"ibtn-back\" onclick=\"goStep(5)\">&larr;</button>\n        <button class=\"ibtn-next\" id=\"btn6\" onclick=\"goStep(7)\" disabled>Review &rarr;</button>\n      </div>\n    </div>\n\n    <!-- STEP 7: SPEC CARD -->\n    <div class=\"istep\" id=\"is7\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.22em;text-transform:uppercase;color:rgba(255,232,168,0.25);margin-bottom:14px\">Contract &mdash; Confirm before building</div>\n      <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(24px,4vw,36px);font-weight:700;line-height:1.0;letter-spacing:-0.03em;margin-bottom:8px\">Before I build,<br><em style=\"font-style:italic;font-weight:200;color:var(--moment)\">confirm this is right.</em></h2>\n      <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);margin-bottom:24px;line-height:1.65\">Read every line. Changes here cost nothing. Changes after the build cost refines.</p>\n      <div style=\"height:1px;background:var(--threshold);margin-bottom:20px\"></div>\n      <div id=\"gapFlags\" style=\"margin-bottom:14px\"></div>\n      <div style=\"background:var(--becoming);border:1px solid var(--threshold);overflow:hidden;margin-bottom:20px\">\n        <div style=\"border-bottom:1px solid var(--threshold);padding:18px 22px;display:flex;align-items:center;gap:14px\">\n          <div style=\"width:28px;height:28px;border-radius:50%;border:1px solid rgba(0,229,255,0.22);background:rgba(0,229,255,0.04);display:flex;align-items:center;justify-content:center;flex-shrink:0\">\n            <div style=\"width:8px;height:8px;border-radius:50%;background:#00E5FF;box-shadow:0 0 6px #00E5FF\"></div>\n          </div>\n          <div>\n            <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(0,229,255,0.35);margin-bottom:3px\">Build contract</div>\n            <div id=\"specTitle\" style=\"font-family:'Fraunces',serif;font-size:16px;font-weight:700;letter-spacing:-0.02em\">Your build</div>\n          </div>\n        </div>\n        <div id=\"specRows\"></div>\n        <div style=\"padding:14px 22px;border-top:1px solid var(--threshold);background:rgba(255,232,168,0.02)\">\n          <div style=\"font-family:'JetBrains Mono',monospace;font-size:9px;letter-spacing:0.10em;color:rgba(232,228,216,0.22);line-height:1.65\">\n            <strong style=\"color:rgba(255,232,168,0.35);font-weight:400\">This is your first render contract.</strong> Every section, interaction, and design decision follows from what you see above.\n          </div>\n        </div>\n      </div>\n      <button class=\"ibtn-build\" onclick=\"startBuild()\">Build it &rarr;</button>\n      <div class=\"inav\" style=\"margin-top:8px\">\n        <button class=\"ibtn-back\" style=\"width:100%\" onclick=\"goStep(6)\">Edit answers</button>\n      </div>\n    </div>\n\n  </div>\n\n  <!-- BUILD ANIMATION SCREEN -->\n  <div id=\"buildScreen\" style=\"display:none;width:100%;max-width:600px;opacity:0;animation:fadeUp 0.6s ease forwards\">\n    <h2 style=\"font-family:'Fraunces',serif;font-size:clamp(28px,5vw,44px);font-weight:700;letter-spacing:-0.04em;line-height:0.95;margin-bottom:10px\">Cipher is <em style=\"font-style:italic;font-weight:200;color:var(--moment)\">building</em><br>your contract.</h2>\n    <p style=\"font-size:14px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.65;margin-bottom:24px\">AAIPE executing. Five layers. Nothing guessed. Everything deliberate.</p>\n    <div style=\"background:var(--becoming);border:1px solid var(--threshold);border-left:2px solid rgba(255,232,168,0.22);padding:18px 22px;margin-bottom:20px\">\n      <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.20em;text-transform:uppercase;color:rgba(255,232,168,0.28);margin-bottom:8px\">Build contract</div>\n      <div id=\"contractText\" style=\"font-size:13px;font-weight:200;color:rgba(232,228,216,0.4);line-height:1.75;font-style:italic\">Assembling...</div>\n    </div>\n    <div style=\"height:1px;background:var(--threshold);overflow:hidden;margin-bottom:5px\"><div id=\"bBar\" style=\"height:100%;background:linear-gradient(to right,var(--moment),rgba(255,232,168,0.3));width:0;transition:width 0.7s ease\"></div></div>\n    <div id=\"bPct\" style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.14em;color:rgba(232,228,216,0.22);text-align:right;margin-bottom:18px\">0%</div>\n    <div style=\"display:flex;flex-direction:column;gap:2px\" id=\"layersList\"></div>\n  </div>\n\n  <!-- SCROLL INDICATOR -->\n  <div style=\"position:absolute;bottom:32px;left:50%;transform:translateX(-50%);display:flex;flex-direction:column;align-items:center;gap:8px;opacity:0.3\" id=\"scrollHint\">\n    <div style=\"font-family:'JetBrains Mono',monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.5)\">Scroll to learn more</div>\n    <div style=\"width:1px;height:32px;background:linear-gradient(var(--moment),transparent)\"></div>\n  </div>\n\n</section>\n\n<!-- BECOMING -->\n<section class=\"g-becoming\">\n  <div class=\"g-becoming-grid\">\n    <div class=\"g-becoming-left g-reveal\">\n      <div class=\"g-becoming-label\" id=\"how\">How it works</div>\n      <h2 class=\"g-becoming-h\">\n        Three steps.<br><em>Zero</em><br>guesswork.\n      </h2>\n      <p class=\"g-becoming-body\">\n        You describe what you are building. Cipher structures it, designs it, and builds it at production quality. Not a mockup. The real thing, in 60 seconds.\n      </p>\n    </div>\n    <div class=\"g-states g-reveal\">\n      <div class=\"g-state\">\n        <div class=\"g-state-progress\"></div>\n        <div class=\"g-state-num\">01 \u2014 PRE-EXISTENCE</div>\n        <div class=\"g-state-title\">You tell Cipher what you are building.</div>\n        <div class=\"g-state-desc\">Seven questions. Each one unlocks the next. No forms, no technical decisions. Just you describing what you see in your head. Cipher listens and structures everything.</div>\n        <div class=\"g-state-indicator\"></div>\n      </div>\n      <div class=\"g-state\">\n        <div class=\"g-state-progress\"></div>\n        <div class=\"g-state-num\">02 \u2014 BECOMING</div>\n        <div class=\"g-state-title\">Cipher builds it at the highest possible quality.</div>\n        <div class=\"g-state-desc\">AAIPE \u2014 Cipher's five-layer build intelligence \u2014 executes your spec. Design system, typography, real photography, live interactions, working data. Nothing placeholder. Nothing generic.</div>\n        <div class=\"g-state-indicator\"></div>\n      </div>\n      <div class=\"g-state\">\n        <div class=\"g-state-progress\"></div>\n        <div class=\"g-state-num\">03 \u2014 EXISTS</div>\n        <div class=\"g-state-title\">Your idea exists. Right now.</div>\n        <div class=\"g-state-desc\">Production-ready. Fully functional. Every button fires. Every tab built. Download the code. Deploy anywhere. Yours forever \u2014 no platform lock-in, no ongoing fee to keep it alive.</div>\n        <div class=\"g-state-indicator\"></div>\n      </div>\n    </div>\n  </div>\n</section>\n\n<!-- THE MOMENT -->\n<section class=\"g-moment-section\">\n  <div class=\"g-moment-label\" id=\"builds\">What gets built</div>\n  <div class=\"g-exist-grid\">\n    <div class=\"g-exist g-reveal\">\n      <div class=\"g-exist-mat\"></div>\n      <div class=\"g-exist-pre\">01 \u2014 Any vision</div>\n      <div class=\"g-exist-num\">50+</div>\n      <div class=\"g-exist-title\">50 categories. Zero generic output.</div>\n      <div class=\"g-exist-body\">Coffee brands, billiards halls, wellness spas, SaaS dashboards, fitness coaches, legal firms, restaurants, portfolios. Every category built to the visual ceiling of that domain \u2014 not a generic template.</div>\n    </div>\n    <div class=\"g-exist g-reveal\">\n      <div class=\"g-exist-mat\"></div>\n      <div class=\"g-exist-pre\">02 \u2014 Any aesthetic</div>\n      <div class=\"g-exist-num\">\u221e</div>\n      <div class=\"g-exist-title\">Matched photography. Real media. Every build.</div>\n      <div class=\"g-exist-body\">Cipher pulls curated Pexels photography matched to your exact business category before a single line of code is written. Hero video backgrounds. Editorial product photography. Real atmosphere, not stock clipart.</div>\n    </div>\n    <div class=\"g-exist g-reveal\">\n      <div class=\"g-exist-mat\"></div>\n      <div class=\"g-exist-pre\">03 \u2014 Any founder</div>\n      <div class=\"g-exist-num\">60s</div>\n      <div class=\"g-exist-title\">Your code. Your domain. Yours forever.</div>\n      <div class=\"g-exist-body\">Download the HTML. Deploy to Vercel, Netlify, or anywhere. No subscription required to keep your site live. No platform lock-in. You own everything built here, permanently.</div>\n    </div>\n  </div>\n</section>\n\n<!-- PROOF -->\n<section class=\"g-proof-section\">\n  <div class=\"g-proof-header g-reveal\">\n    <h2 class=\"g-proof-h\">Things that<br><em>became real.</em></h2>\n    <p class=\"g-proof-note\" id=\"proof\">Built on SOVREND. Live in the world.</p>\n  </div>\n  <div class=\"g-evidence\">\n    <div class=\"g-evidence-item g-reveal\">\n      <div class=\"g-evidence-moment\">Became real \u00b7 Oct 2025</div>\n      <p class=\"g-evidence-quote\">\"I described it at 11pm. By midnight it was live. The investors saw it the next morning and asked who our designer was.\"</p>\n      <div class=\"g-evidence-from\"><span class=\"g-evidence-name\">Sarah Chen</span> \u00b7 CEO, DataFlow</div>\n      <div class=\"g-evidence-outcome\">$18K MRR after launch</div>\n    </div>\n    <div class=\"g-evidence-item g-reveal\">\n      <div class=\"g-evidence-moment\">Became real \u00b7 Oct 2025</div>\n      <p class=\"g-evidence-quote\">\"Four hours. Complete MVP. Working dashboard, real data, nothing placeholder. We raised $340K two weeks later showing that build.\"</p>\n      <div class=\"g-evidence-from\"><span class=\"g-evidence-name\">Marcus Rivera</span> \u00b7 Founder, ScheduleFlow</div>\n      <div class=\"g-evidence-outcome\">$24K MRR \u00b7 $340K raised</div>\n    </div>\n    <div class=\"g-evidence-item g-reveal\">\n      <div class=\"g-evidence-moment\">Became real \u00b7 Nov 2025</div>\n      <p class=\"g-evidence-quote\">\"Every other builder gave me the same thing. SOVREND gave me something that felt like mine. Like it understood what I was trying to say.\"</p>\n      <div class=\"g-evidence-from\"><span class=\"g-evidence-name\">Priya Nair</span> \u00b7 Founder, Meridian</div>\n      <div class=\"g-evidence-outcome\">$31K MRR \u00b7 Series A in progress</div>\n    </div>\n  </div>\n</section>\n\n<!-- FINAL -->\n<section class=\"g-final\">\n  <div class=\"g-final-field\"></div>\n  <div class=\"g-final-pre\">Start building</div>\n  <h2 class=\"g-final-h\">\n    <span class=\"g-final-line1\">Your idea</span>\n    <span class=\"g-final-line2\">already</span>\n    <span class=\"g-final-line3\">exists.</span>\n  </h2>\n  <div class=\"g-final-pause\"></div>\n  <p class=\"g-final-sub\">Cipher is ready. One free build. No credit card required.</p>\n  <button class=\"g-final-btn\" onclick=\"document.getElementById('cipher-hero').scrollIntoView({behavior:'smooth'})\">Build it now \u2192</button>\n  <div class=\"g-final-trust\">\n    <span>No credit card</span>\n    <span>\u00b7</span>\n    <span>Cancel anytime</span>\n    <span>\u00b7</span>\n    <span>Your code, always</span>\n  </div>\n</section>\n\n<!-- FOOTER -->\n<footer class=\"g-footer\">\n  <div class=\"g-footer-logo\">SOVREND</div>\n  <div class=\"g-footer-copy\">\u00a9 2026 SOVREND INC &middot; THE PLACE WHERE THE THOUGHT BECOMES THE THING</div>\n</footer>\n\n<script>\n// CURSOR \u2014 assembles toward what it approaches\nconst cur = document.getElementById('g-cursor');\nconst core = cur.querySelector('.gc-core');\nconst field = cur.querySelector('.gc-field');\nlet mx=window.innerWidth/2, my=window.innerHeight/2;\nlet fx=mx, fy=my;\n\ndocument.addEventListener('mousemove', e => {\n  mx=e.clientX; my=e.clientY;\n  cur.style.left=mx+'px'; cur.style.top=my+'px';\n});\n\nfunction lerpField() {\n  fx += (mx-fx)*0.08; fy += (my-fy)*0.08;\n  field.style.left=(fx-mx)+'px'; field.style.top=(fy-my)+'px';\n  requestAnimationFrame(lerpField);\n}\nlerpField();\n\ndocument.querySelectorAll('button,a,.g-state,.g-exist,.g-evidence-item').forEach(el => {\n  el.addEventListener('mouseenter', () => {\n    core.style.transform='translate(-50%,-50%) scale(3)';\n    core.style.boxShadow='0 0 20px rgba(255,232,168,0.6),0 0 40px rgba(255,232,168,0.3)';\n    field.style.transform='translate(-50%,-50%) scale(0.4)';\n    field.style.borderColor='rgba(255,232,168,0.5)';\n  });\n  el.addEventListener('mouseleave', () => {\n    core.style.transform='translate(-50%,-50%) scale(1)';\n    core.style.boxShadow='0 0 8px rgba(255,232,168,0.5),0 0 20px rgba(255,232,168,0.3)';\n    field.style.transform='translate(-50%,-50%) scale(1)';\n    field.style.borderColor='rgba(255,232,168,0.15)';\n  });\n});\n\n// CANVAS \u2014 particles in pre-existence state\nconst canvas = document.getElementById('g-canvas');\nconst ctx = canvas.getContext('2d');\nlet W, H, particles=[], connections=[];\nfunction resize() { W=canvas.width=window.innerWidth; H=canvas.height=window.innerHeight; }\nresize(); window.addEventListener('resize', resize);\n\nclass Particle {\n  constructor() { this.init(); }\n  init() {\n    this.x = Math.random()*W; this.y = Math.random()*H;\n    this.vx = (Math.random()-.5)*0.2; this.vy = (Math.random()-.5)*0.2;\n    this.size = Math.random()*1.2+0.2;\n    // Particles exist in different states of becoming\n    this.state = Math.random(); // 0=pre, 0.5=becoming, 1=existing\n    this.targetState = Math.random();\n    this.stateSpeed = 0.002+Math.random()*0.003;\n    this.alpha = 0;\n  }\n  update() {\n    this.x+=this.vx; this.y+=this.vy;\n    // State evolution\n    this.state += (this.targetState-this.state)*this.stateSpeed;\n    if(Math.abs(this.state-this.targetState)<0.01) {\n      this.targetState = Math.random();\n    }\n    // Alpha based on state\n    this.alpha = this.state*0.4+0.02;\n    // Mouse field influence\n    const dx=mx-this.x, dy=my-this.y;\n    const d=Math.sqrt(dx*dx+dy*dy);\n    if(d<200) {\n      // Particles assemble slightly toward cursor\n      this.vx += dx/d*0.008*(1-d/200);\n      this.vy += dy/d*0.008*(1-d/200);\n      // They also brighten near cursor\n      this.alpha = Math.min(this.alpha+(1-d/200)*0.3, 0.7);\n    }\n    this.vx*=0.99; this.vy*=0.99;\n    if(this.x<0||this.x>W||this.y<0||this.y>H) this.init();\n  }\n  draw() {\n    // Color based on state \u2014 pre=cold white, becoming=warm, existing=amber\n    const r = Math.floor(232 + this.state*23);\n    const g = Math.floor(228 + this.state*4);\n    const b = Math.floor(216 - this.state*48);\n    ctx.beginPath();\n    ctx.arc(this.x, this.y, this.size, 0, Math.PI*2);\n    ctx.fillStyle = `rgba(${r},${g},${b},${this.alpha})`;\n    ctx.fill();\n  }\n}\n\nfor(let i=0;i<200;i++) particles.push(new Particle());\n\n// Occasional \"becoming\" flash \u2014 a particle suddenly exists\nlet flashes = [];\nfunction createFlash() {\n  flashes.push({\n    x:Math.random()*W, y:Math.random()*H,\n    life:1, size:0\n  });\n}\nsetInterval(createFlash, 600);\n\nfunction draw() {\n  ctx.clearRect(0,0,W,H);\n\n  // Connections between close particles \u2014 threads of potential\n  for(let i=0;i<particles.length;i+=2) {\n    for(let j=i+1;j<particles.length;j+=2) {\n      const dx=particles[i].x-particles[j].x;\n      const dy=particles[i].y-particles[j].y;\n      const d=Math.sqrt(dx*dx+dy*dy);\n      if(d<80) {\n        const combined = (particles[i].state+particles[j].state)/2;\n        ctx.beginPath();\n        ctx.moveTo(particles[i].x,particles[i].y);\n        ctx.lineTo(particles[j].x,particles[j].y);\n        const alpha=(1-d/80)*combined*0.06;\n        ctx.strokeStyle=`rgba(255,232,168,${alpha})`;\n        ctx.lineWidth=0.5;\n        ctx.stroke();\n      }\n    }\n  }\n\n  particles.forEach(p=>{p.update();p.draw();});\n\n  // Becoming flashes\n  flashes = flashes.filter(f=>f.life>0.02);\n  flashes.forEach(f=>{\n    f.size += 8*f.life;\n    f.life *= 0.88;\n    ctx.beginPath();\n    ctx.arc(f.x,f.y,f.size,0,Math.PI*2);\n    ctx.fillStyle=`rgba(255,232,168,${f.life*0.06})`;\n    ctx.fill();\n    // Inner glow\n    ctx.beginPath();\n    ctx.arc(f.x,f.y,f.size*0.3,0,Math.PI*2);\n    ctx.fillStyle=`rgba(255,255,255,${f.life*0.12})`;\n    ctx.fill();\n  });\n\n  ctx.globalAlpha=1;\n  requestAnimationFrame(draw);\n}\ndraw();\n\n// NAV scroll\nwindow.addEventListener('scroll', ()=>{\n  document.getElementById('g-nav').classList.toggle('solid', window.scrollY>50);\n});\n\n// REVEAL\nconst io = new IntersectionObserver(entries=>{\n  entries.forEach((e,i)=>{\n    if(e.isIntersecting) {\n      setTimeout(()=>e.target.classList.add('in'), i*100);\n      io.unobserve(e.target);\n    }\n  });\n},{threshold:0.1});\ndocument.querySelectorAll('.g-reveal').forEach(el=>io.observe(el));\n\n\n\n/* \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\n   CIPHER INTAKE \u2014 Landing Page\n   \u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550\u2550 */\n\nvar iStep = 0;\nvar iPath = '';\nvar iVibe = '';\nvar iAction = '';\nvar ITOTAL = 7;\nvar fd = {name:'',desc:'',offers:[],s2:'',ref:'',edge:'',clarify:''};\n\nvar iVoices = {\n  0: \"What are you building? Every path leads to the same quality. This just tells me how to structure what follows.\",\n  1: \"Good. Now tell me what to call it and one sentence about who it serves.\",\n  2: \"Perfect. What do you actually offer? This becomes the architecture of every section I build.\",\n  3: \"The best products are felt before they are read. Choose the emotional territory.\",\n  4: \"Every section I build points toward this moment. What action do you want visitors to take?\",\n  5: \"This is where your build becomes yours or becomes generic. Be specific here.\",\n  6: \"One last thing before I start. This goes straight into your hero copy.\",\n  7: \"Everything looks right. One click and I start building.\"\n};\n\nvar iPathActions = {\n  product:[\n    {id:'buy',name:'Buy Now',desc:'Direct purchase. Commerce-first structure.'},\n    {id:'subscribe',name:'Subscribe',desc:'Recurring revenue. The long relationship.'},\n    {id:'learn',name:'Learn More',desc:'Education-first. Earned trust before the ask.'},\n    {id:'waitlist',name:'Join Waitlist',desc:'Not live yet. Capture demand now.'}\n  ],\n  service:[\n    {id:'book',name:'Book a Call',desc:'High-ticket consult. Relationship-first.'},\n    {id:'contact',name:'Start a Conversation',desc:'Lead capture. The relationship begins here.'},\n    {id:'apply',name:'Apply to Work Together',desc:'Selective. Builds authority and demand.'},\n    {id:'portfolio',name:'See My Work',desc:'Portfolio-first. Let the work close.'}\n  ],\n  software:[\n    {id:'signup',name:'Start Free',desc:'Low friction. Get them in the product.'},\n    {id:'demo',name:'Book a Demo',desc:'Enterprise. Human-assisted conversion.'},\n    {id:'waitlist',name:'Join Waitlist',desc:'Pre-launch. Capture early adopters.'},\n    {id:'trial',name:'Start Free Trial',desc:'Let the product sell itself.'}\n  ],\n  launch:[\n    {id:'waitlist',name:'Join Waitlist',desc:'Capture demand before you exist.'},\n    {id:'earlyaccess',name:'Get Early Access',desc:'Exclusive. Builds anticipation.'},\n    {id:'invest',name:'Learn to Invest',desc:'Raising capital. Serious operators.'},\n    {id:'notify',name:'Notify Me',desc:'Soft commitment. Maximum reach.'}\n  ]\n};\n\nvar iPathClarify = {\n  product: \"What is the single feeling you want someone to have the moment they see your product?\",\n  service: \"What is the single outcome your best client achieved working with you? Be specific.\",\n  software: \"Who is your most frustrated potential user and what exactly are they frustrated about?\",\n  launch: \"What do you want the first person on your waitlist to tell their friend about you?\"\n};\n\nvar iActionLabels = {\n  buy:'Buy Now',subscribe:'Subscribe',learn:'Learn More',waitlist:'Join Waitlist',\n  book:'Book a Call',contact:'Start a Conversation',apply:'Apply to Work Together',\n  portfolio:'See My Work',signup:'Start Free',demo:'Book a Demo',\n  trial:'Start Free Trial',earlyaccess:'Get Early Access',invest:'Learn to Invest',notify:'Notify Me'\n};\n\n/* VOICE */\nvar iTypeTimer = null;\nfunction iTypeVoice(text) {\n  var el = document.getElementById('cipherVoice');\n  if (!el) return;\n  el.innerHTML = '';\n  clearTimeout(iTypeTimer);\n  var i = 0;\n  var cursor = document.createElement('span');\n  cursor.className = 'tcursor';\n  function go() {\n    if (i < text.length) {\n      el.textContent = text.slice(0, i+1);\n      el.appendChild(cursor);\n      i++;\n      iTypeTimer = setTimeout(go, 14 + Math.random()*8);\n    } else {\n      el.appendChild(cursor);\n    }\n  }\n  setTimeout(go, 100);\n}\n\n/* PROGRESS */\nfunction buildProg() {\n  var row = document.getElementById('progRow');\n  if (!row) return;\n  row.innerHTML = '';\n  for (var i = 0; i < ITOTAL; i++) {\n    var seg = document.createElement('div');\n    seg.className = 'prog-seg' + (i < iStep ? ' done' : i === iStep ? ' active' : '');\n    row.appendChild(seg);\n  }\n}\n\n/* STEP NAV */\nfunction goStep(n) {\n  if (n === 2) buildS2();\n  if (n === 4) buildActions();\n  if (n === 6) buildClarify();\n  if (n === 7) buildSpec();\n  var cur = document.getElementById('is' + iStep);\n  if (cur) cur.classList.remove('active');\n  iStep = n;\n  var next = document.getElementById('is' + n);\n  if (next) {\n    next.classList.add('active');\n    var inp = next.querySelector('.ifield');\n    if (inp) setTimeout(function(){ inp.focus(); }, 350);\n  }\n  buildProg();\n  if (iVoices[n]) iTypeVoice(iVoices[n]);\n  window.scrollTo({top: document.getElementById('cipher-hero').offsetTop - 80, behavior: 'smooth'});\n}\n\n/* PATH */\nfunction pickPath(el) {\n  document.querySelectorAll('.pcard').forEach(function(c){ c.classList.remove('on'); });\n  el.classList.add('on');\n  iPath = el.getAttribute('data-path');\n  var msgs = {\n    product:\"Selling something. I will build commerce-first \u2014 product grid, cart, checkout, the works.\",\n    service:\"Selling expertise. Every section builds credibility and ends in a booking moment.\",\n    software:\"Launching software. Clean, modern, product-led. Features that sell themselves.\",\n    launch:\"Launching an idea. Pre-launch architecture \u2014 waitlist, social proof, early momentum.\"\n  };\n  var hint = document.getElementById('pathHint');\n  if (hint) { hint.textContent = msgs[iPath] || ''; hint.style.color = 'rgba(255,232,168,0.4)'; }\n  var btn = document.getElementById('btn0');\n  if (btn) btn.disabled = false;\n}\n\n/* NAME + DESC */\nfunction validateName() {\n  var v = document.getElementById('iName').value.trim();\n  fd.name = v;\n  var inp = document.getElementById('iName');\n  var hint = document.getElementById('nameHint');\n  if (v.length >= 2) {\n    inp.className = 'ifield valid';\n    hint.textContent = 'Good name. Now describe what it does.';\n    hint.style.color = 'rgba(46,125,82,0.7)';\n  } else if (v.length > 0) {\n    inp.className = 'ifield err';\n    hint.textContent = 'A little short.';\n    hint.style.color = 'rgba(184,50,50,0.6)';\n  } else {\n    inp.className = 'ifield';\n    hint.textContent = '';\n  }\n  checkStep1();\n}\nfunction validateDesc() {\n  var v = document.getElementById('iDesc').value.trim();\n  fd.desc = v;\n  var inp = document.getElementById('iDesc');\n  if (v.length >= 15) inp.className = 'ifield valid';\n  else if (v.length > 0) inp.className = 'ifield';\n  else inp.className = 'ifield';\n  checkStep1();\n}\nfunction checkStep1() {\n  var btn = document.getElementById('btn1');\n  if (btn) btn.disabled = !(fd.name.length >= 2 && fd.desc.length >= 10);\n}\n\n/* S2 CONTENT */\nfunction buildS2() {\n  var c = document.getElementById('s2content');\n  if (!c || !iPath) return;\n  var h = '';\n  if (iPath === 'product') {\n    h += \"<div style='display:flex;flex-direction:column;gap:5px;margin-bottom:8px' id='offerTbl'>\";\n    h += \"<div style='display:grid;grid-template-columns:1fr 90px;gap:5px'><input class='ifield' placeholder='Product name' data-o='n' oninput='syncOffers()'><input class='ifield' placeholder='Price' data-o='p'></div>\";\n    h += \"<div style='display:grid;grid-template-columns:1fr 90px;gap:5px'><input class='ifield' placeholder='Product name' data-o='n' oninput='syncOffers()'><input class='ifield' placeholder='Price' data-o='p'></div>\";\n    h += \"<div style='display:grid;grid-template-columns:1fr 90px;gap:5px'><input class='ifield' placeholder='Product name' data-o='n' oninput='syncOffers()'><input class='ifield' placeholder='Price' data-o='p'></div>\";\n    h += \"</div>\";\n    h += \"<button onclick='addOffer()' style='background:none;border:1px dashed rgba(255,232,168,0.1);padding:10px;width:100%;font-family:monospace;font-size:8px;letter-spacing:0.16em;text-transform:uppercase;color:rgba(255,232,168,0.22);cursor:pointer;transition:all 0.3s;margin-bottom:6px'>+ Add another item</button>\";\n    h += \"<div style='font-family:monospace;font-size:9px;letter-spacing:0.10em;color:rgba(232,228,216,0.22)'>List everything you offer. Leave empty rows blank.</div>\";\n  } else if (iPath === 'service') {\n    h += \"<div style='margin-bottom:10px'><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>What you offer</label><textarea class='ifield' id='s2svc' rows='3' placeholder='Describe your service, packages, or how people work with you. Include pricing if you have it.' oninput='syncS2()'></textarea></div>\";\n    h += \"<div><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Who you work best with</label><input class='ifield' id='s2ideal' placeholder='Describe your ideal client in one sentence.' oninput='syncS2()'></div>\";\n  } else if (iPath === 'software') {\n    h += \"<div style='margin-bottom:10px'><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Core capabilities</label><textarea class='ifield' id='s2feat' rows='3' placeholder='What are the 3-5 most important things your software does? What does it make possible?' oninput='syncS2()'></textarea></div>\";\n    h += \"<div style='margin-bottom:10px'><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Who uses it</label><input class='ifield' id='s2users' placeholder='Job title or type of person. Be specific.' oninput='syncS2()'></div>\";\n    h += \"<div><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Pricing model (optional)</label><input class='ifield' id='s2price' placeholder='Free tier, monthly, one-time, usage-based...'></div>\";\n  } else {\n    h += \"<div style='margin-bottom:10px'><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>What you are building</label><textarea class='ifield' id='s2vision' rows='3' placeholder='Describe what this is in detail. What does it do, who is it for, what problem does it solve?' oninput='syncS2()'></textarea></div>\";\n    h += \"<div style='margin-bottom:10px'><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Where it is now</label><input class='ifield' id='s2stage' placeholder='e.g. Raising funding, building MVP, pre-launch...'></div>\";\n    h += \"<div><label style='font-family:monospace;font-size:8px;letter-spacing:0.18em;text-transform:uppercase;color:rgba(232,228,216,0.28);display:block;margin-bottom:8px'>Launch timeline (optional)</label><input class='ifield' id='s2time' placeholder='e.g. Q2 2026, this summer...'></div>\";\n  }\n  c.innerHTML = h;\n}\nfunction addOffer() {\n  var t = document.getElementById('offerTbl');\n  if (!t) return;\n  var row = document.createElement('div');\n  row.style.cssText = 'display:grid;grid-template-columns:1fr 90px;gap:5px';\n  row.innerHTML = \"<input class='ifield' placeholder='Product name' data-o='n' oninput='syncOffers()'><input class='ifield' placeholder='Price' data-o='p'>\";\n  t.appendChild(row);\n}\nfunction syncOffers() {\n  var ns = document.querySelectorAll(\"[data-o='n']\");\n  var ps = document.querySelectorAll(\"[data-o='p']\");\n  fd.offers = [];\n  for (var i = 0; i < ns.length; i++) {\n    var on = ns[i].value.trim();\n    if (on) fd.offers.push(on + (ps[i] && ps[i].value ? ' (' + ps[i].value.trim() + ')' : ''));\n  }\n}\nfunction syncS2() {\n  var ids = ['s2svc','s2ideal','s2feat','s2users','s2price','s2vision','s2stage','s2time'];\n  var parts = [];\n  ids.forEach(function(id){ var el = document.getElementById(id); if(el && el.value.trim()) parts.push(el.value.trim()); });\n  fd.s2 = parts.join(' ');\n}\n\n/* VIBE */\nfunction pickVibe(el) {\n  document.querySelectorAll('.vcard').forEach(function(c){ c.classList.remove('on'); });\n  el.classList.add('on');\n  iVibe = el.getAttribute('data-vibe');\n  var btn = document.getElementById('btn3');\n  if (btn) btn.disabled = false;\n  fd.ref = document.getElementById('iRef') ? document.getElementById('iRef').value.trim() : '';\n}\n\n/* ACTIONS */\nfunction buildActions() {\n  var grid = document.getElementById('actionGrid');\n  if (!grid || !iPath) return;\n  var acts = iPathActions[iPath] || [];\n  grid.innerHTML = acts.map(function(a){\n    return \"<div class='acard' data-action='\" + a.id + \"' onclick='pickAction(this)'>\"\n      + \"<div class='acheck'>&#10003;</div>\"\n      + \"<div style='font-family:serif;font-size:16px;font-weight:700;letter-spacing:-0.02em;line-height:1.1;margin-bottom:4px'>\" + a.name + \"</div>\"\n      + \"<div style='font-size:12px;font-weight:200;color:rgba(232,228,216,0.4)'>\" + a.desc + \"</div>\"\n      + \"</div>\";\n  }).join('');\n}\nfunction pickAction(el) {\n  document.querySelectorAll('.acard').forEach(function(c){ c.classList.remove('on'); });\n  el.classList.add('on');\n  iAction = el.getAttribute('data-action');\n  var btn = document.getElementById('btn4');\n  if (btn) btn.disabled = false;\n}\n\n/* EDGE */\nfunction validateEdge() {\n  fd.edge = document.getElementById('iEdge').value.trim();\n  var btn = document.getElementById('btn5');\n  if (btn) btn.disabled = fd.edge.length < 20;\n  var inp = document.getElementById('iEdge');\n  var hint = document.getElementById('edgeHint');\n  if (fd.edge.length >= 20) {\n    inp.className = 'ifield valid';\n    hint.textContent = 'That is enough to work with. The more specific the better.';\n    hint.style.color = 'rgba(46,125,82,0.7)';\n  } else if (fd.edge.length > 0) {\n    inp.className = 'ifield';\n    hint.textContent = 'Keep going. Generic in, generic out.';\n    hint.style.color = 'rgba(232,228,216,0.22)';\n  }\n}\n\n/* CLARIFY */\nfunction buildClarify() {\n  var q = document.getElementById('clarifyQ');\n  if (q && iPathClarify[iPath]) q.textContent = iPathClarify[iPath];\n}\nfunction validateClarify() {\n  fd.clarify = document.getElementById('iClarify').value.trim();\n  var btn = document.getElementById('btn6');\n  if (btn) btn.disabled = fd.clarify.length < 10;\n  if (fd.clarify.length >= 10) document.getElementById('iClarify').className = 'ifield valid';\n}\n\n/* ENTER KEY */\nfunction enterNext(e, n) {\n  if (e.key === 'Enter' && !e.shiftKey) {\n    e.preventDefault();\n    var btn = document.getElementById('btn' + (n-1));\n    if (btn && !btn.disabled) goStep(n);\n  }\n}\n\n/* SPEC CARD */\nfunction buildSpec() {\n  syncOffers();\n  syncS2();\n  fd.ref = document.getElementById('iRef') ? document.getElementById('iRef').value.trim() : '';\n  fd.edge = document.getElementById('iEdge') ? document.getElementById('iEdge').value.trim() : '';\n  fd.clarify = document.getElementById('iClarify') ? document.getElementById('iClarify').value.trim() : '';\n\n  var vmL = {dark:'Dark & Cinematic',light:'Light & Editorial',bold:'Bold & Modern',organic:'Warm & Organic'};\n  var pmL = {product:'E-Commerce / Product',service:'Service Business',software:'SaaS / Software',launch:'Pre-Launch / Idea'};\n  var bpL = {product:'Commerce Store',service:'Service & Credibility',software:'SaaS Product',launch:'Launch & Validation'};\n\n  var title = document.getElementById('specTitle');\n  if (title) title.textContent = fd.name || (pmL[iPath] || 'Your Build');\n\n  var gaps = [];\n  if (!fd.name) gaps.push({k:'Brand name', m:'No brand name entered. I will use a placeholder.'});\n  if (!fd.desc) gaps.push({k:'Description', m:'No description entered. Hero copy will be generic.'});\n  if (!iVibe) gaps.push({k:'Aesthetic', m:'No visual direction selected. I will choose based on category.'});\n\n  var gf = document.getElementById('gapFlags');\n  if (gf) gf.innerHTML = gaps.map(function(g){\n    return \"<div class='gap-flag'><div class='gap-icon'>!</div><div class='gap-txt'><strong>\" + g.k + \"</strong> &mdash; \" + g.m + \"</div></div>\";\n  }).join('');\n\n  var offDisp = fd.offers.length ? fd.offers.slice(0,4).map(function(o){ return \"<span class='spec-tag'>\" + o + \"</span>\"; }).join('') : '<em style=\"color:rgba(232,228,216,0.28)\">None entered</em>';\n\n  var rows = [\n    {k:'Blueprint', v: bpL[iPath] || 'Custom'},\n    {k:'Brand', v: fd.name || '<em style=\"color:rgba(232,228,216,0.28)\">Not entered</em>'},\n    {k:'Type', v: pmL[iPath] || iPath},\n    {k:'Aesthetic', v: vmL[iVibe] || '<em style=\"color:rgba(232,228,216,0.28)\">Not selected</em>'},\n    {k:'Primary CTA', v: iActionLabels[iAction] || '<em style=\"color:rgba(232,228,216,0.28)\">Not selected</em>'},\n    {k:'Offerings', v: offDisp},\n    {k:'Edge', v: fd.edge ? '<em>' + fd.edge.slice(0,80) + (fd.edge.length > 80 ? '...' : '') + '</em>' : '<em style=\"color:rgba(232,228,216,0.28)\">Not entered</em>'},\n    {k:'Hero Voice', v: fd.clarify ? '<em>' + fd.clarify.slice(0,80) + (fd.clarify.length > 80 ? '...' : '') + '</em>' : '<em style=\"color:rgba(232,228,216,0.28)\">Not entered</em>'},\n    {k:'Photography', v: 'Curated editorial &mdash; matched to ' + (pmL[iPath] || 'your build type')},\n    {k:'Reference', v: fd.ref || '<em style=\"color:rgba(232,228,216,0.28)\">Cipher selects</em>'}\n  ];\n\n  var sr = document.getElementById('specRows');\n  if (sr) sr.innerHTML = rows.map(function(r){\n    return \"<div class='spec-row'><div class='spec-k'>\" + r.k + \"</div><div class='spec-v'>\" + r.v + \"</div></div>\";\n  }).join('');\n}\n\n/* BRIEF ASSEMBLY */\nfunction buildBrief() {\n  var vmMap = {dark:'dark cinematic premium',light:'light editorial warm',bold:'bold modern high-energy',organic:'warm organic natural'};\n  var amMap = {buy:'Buy Now',subscribe:'Subscribe',learn:'Learn More',waitlist:'Join Waitlist',book:'Book a Call',contact:'Start a Conversation',apply:'Apply to Work Together',portfolio:'See My Work',signup:'Start Free',demo:'Book a Demo',trial:'Start Free Trial',earlyaccess:'Get Early Access',invest:'Learn to Invest',notify:'Notify Me'};\n  var pmMap = {product:'product/ecommerce',service:'service business',software:'SaaS/software',launch:'pre-launch'};\n  var parts = [];\n  if (fd.name) parts.push('Build a ' + (vmMap[iVibe] || 'professional') + ' ' + (pmMap[iPath] || '') + ' website for ' + fd.name + '.');\n  if (fd.desc) parts.push(fd.desc);\n  if (fd.offers.length) parts.push('Offerings: ' + fd.offers.join(', ') + '.');\n  if (fd.s2) parts.push(fd.s2);\n  if (iAction) parts.push('Primary conversion: ' + (amMap[iAction] || iAction) + '.');\n  if (fd.edge) parts.push(fd.edge);\n  if (fd.clarify) parts.push('Hero direction: ' + fd.clarify + '.');\n  if (fd.ref) parts.push('Design reference: ' + fd.ref + '.');\n  return parts.join(' ') || 'Building your vision...';\n}\n\n/* BUILD */\nfunction startBuild() {\n  var brief = buildBrief();\n  document.getElementById('intakeWrap').style.display = 'none';\n  document.getElementById('buildScreen').style.display = 'block';\n  document.getElementById('contractText').textContent = brief;\n  iTypeVoice('Contract locked. AAIPE executing. Five layers. Nothing guessed. Everything deliberate.');\n\n  var layerDefs = [\n    {n:'01', name:'Analyze \u2014 Extracting intent and requirements', start:400, dur:1000, done:'Analyzed'},\n    {n:'02', name:'Architect \u2014 Selecting blueprint and structure', start:1600, dur:1200, done:'Matched'},\n    {n:'03', name:'Implement \u2014 Generating production output', start:3000, dur:3000, done:'Generated'},\n    {n:'04', name:'Polish \u2014 Applying design system', start:6200, dur:1100, done:'Polished'},\n    {n:'05', name:'Evaluate \u2014 Scoring and surfacing pathways', start:7500, dur:700, done:'Scored'}\n  ];\n\n  var ll = document.getElementById('layersList');\n  if (ll) ll.innerHTML = layerDefs.map(function(l){\n    return \"<div class='layer-row' id='lr\"+l.n+\"'>\"\n      + \"<div style='font-family:monospace;font-size:8px;letter-spacing:0.10em;color:rgba(232,228,216,0.22);width:16px;flex-shrink:0'>\" + l.n + \"</div>\"\n      + \"<div style='font-size:13px;font-weight:300;color:rgba(232,228,216,0.35);flex:1'>\" + l.name + \"</div>\"\n      + \"<div id='ls\"+l.n+\"' style='font-family:monospace;font-size:8px;letter-spacing:0.12em;text-transform:uppercase;color:rgba(232,228,216,0.22)'>Waiting</div>\"\n      + \"<div class='lspin'></div>\"\n      + \"</div>\";\n  }).join('');\n\n  var bar = document.getElementById('bBar');\n  var pct = document.getElementById('bPct');\n\n  layerDefs.forEach(function(l, idx) {\n    setTimeout(function(){\n      var row = document.getElementById('lr' + l.n);\n      var state = document.getElementById('ls' + l.n);\n      if (row) row.classList.add('active');\n      if (state) state.textContent = 'Running';\n      var p = (idx+1)/layerDefs.length*100;\n      if (bar) bar.style.width = (p*0.85) + '%';\n      if (pct) pct.textContent = Math.round(p*0.85) + '%';\n      setTimeout(function(){\n        if (row) { row.classList.remove('active'); row.classList.add('done'); }\n        if (state) state.textContent = l.done;\n        if (bar) bar.style.width = p + '%';\n        if (pct) pct.textContent = Math.round(p) + '%';\n        if (idx === layerDefs.length - 1) {\n          setTimeout(function(){\n            iTypeVoice(fd.name + ' is ready. Taking you to your dashboard now.');\n            setTimeout(function(){\n              localStorage.setItem('sovrend_brief', brief); localStorage.setItem('sovrend_intake', JSON.stringify({q1: typeof fd !== 'undefined' ? (fd.name||'') : '', q2: typeof fd !== 'undefined' ? (fd.diff||'') : '', q3: typeof fd !== 'undefined' ? (fd.customer||'') : '', q4: typeof fd !== 'undefined' ? (fd.palette||'') : '', q5: typeof fd !== 'undefined' ? (fd.avoid||'') : ''})); window.location.href = '/dashboard';\n            }, 2200);\n          }, 500);\n        }\n      }, l.dur);\n    }, l.start);\n  });\n}\n\n/* INIT */\nbuildProg();\niTypeVoice(iVoices[0]);\n\n// Hide scroll hint when user starts interacting\ndocument.getElementById('intakeWrap').addEventListener('click', function(){\n  var h = document.getElementById('scrollHint');\n  if (h) h.style.opacity = '0';\n});\n\n\n// Materialization hover for exist cells\ndocument.querySelectorAll('.g-exist').forEach(el=>{\n  el.addEventListener('mousemove', e=>{\n    const rect=el.getBoundingClientRect();\n    const x=((e.clientX-rect.left)/rect.width)*100;\n    const y=((e.clientY-rect.top)/rect.height)*100;\n    el.querySelector('.g-exist-mat').style.background=\n      `radial-gradient(circle at ${x}% ${y}%, rgba(255,232,168,0.05) 0%, transparent 60%)`;\n  });\n});\n</script>\n</body>\n</html>\n"

export default function HomePage() {
  useEffect(() => {
    document.open()
    document.write(GENESIS_HTML)
    document.close()
  }, [])
  return <div style={{background:'#0B0D14',minHeight:'100vh'}} />
}
